class AdaptiveRouter:
    TIERS = {
        "high":   (0.55, {"en","fr","de","es","pt"}),
        "medium": (0.40, {"ta","hi","ko","ja","zh"}),
        "low":    (0.30, {"sw","yo","th","vi"}),
    }

    def get_threshold(self, lang):
        for min_score, langs in self.TIERS.values():
            if lang in langs:
                return min_score
        return 0.35

    def should_accept(self, score, lang):
        return score >= self.get_threshold(lang)

router = AdaptiveRouter()
print(router.get_threshold("fr"))   # 0.55
print(router.get_threshold("ta"))   # 0.40
print(router.should_accept(0.45, "fr"))  # False
print(router.should_accept(0.45, "ta"))  # True

