class AdaptiveRetrievalRouter:
    LANG_TIERS = {
        "en": 0.55, "fr": 0.55, "de": 0.55, "es": 0.55,
        "ta": 0.40, "hi": 0.40, "ko": 0.40, "ja": 0.40,
        "sw": 0.30, "yo": 0.30, "th": 0.30,
    }
    DEFAULT_THRESHOLD = 0.35

    def get_threshold(self, lang_code):
        return self.LANG_TIERS.get(lang_code, self.DEFAULT_THRESHOLD)

    def filter_results(self, results, lang_code):
        t = self.get_threshold(lang_code)
        return [r for r in results if r["score"] >= t]

    def route(self, results, lang_code):
        t = self.get_threshold(lang_code)
        filtered = [r for r in results if r["score"] >= t]
        if filtered:
            return {"results": filtered, "strategy": "direct", "threshold": t}
        relaxed_t = t * 0.8
        filtered = [r for r in results if r["score"] >= relaxed_t]
        if filtered:
            return {"results": filtered, "strategy": "fallback", "threshold": relaxed_t}
        return {"results": [], "strategy": "escalate", "threshold": t}

